# Run the tests manually
from django.test.utils import setup_test_environment
setup_test_environment()

# Now test
from functools import wraps, update_wrapper
from django.utils.decorators import method_decorator

# Test 1: Basic decorator with @wraps
print('Test 1: Basic decorator with @wraps')
def logger(func):
    @wraps(func)
    def inner(*args, **kwargs):
        try:
            result = func(*args, **kwargs)
        except Exception as e:
            result = str(e)
        finally:
            pass
        return result
    return inner

class Test1:
    @method_decorator(logger)
    def hello_world(self):
        return 'hello'

t1 = Test1()
result = t1.hello_world()
print(f'  Result: {result}')
print(f'  __name__: {Test1.hello_world.__name__}')
assert result == 'hello', f'Expected hello, got {result}'
print('  PASS')

# Test 2: Multiple decorators
print('Test 2: Multiple decorators')
def add_exclamation(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs) + '!'
    return wrapper

def add_question(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs) + '?'
    return wrapper

class Test2:
    @method_decorator([add_exclamation, add_question])
    def hello(self):
        return 'hello'

t2 = Test2()
result = t2.hello()
print(f'  Result: {result}')
assert result == 'hello?!', f'Expected hello?!, got {result}'
print('  PASS')

# Test 3: Class decoration
print('Test 3: Class decoration')
@method_decorator(logger, name='greet')
class Test3:
    def greet(self):
        return 'greetings'

t3 = Test3()
result = t3.greet()
print(f'  Result: {result}')
print(f'  __name__: {Test3.greet.__name__}')
assert result == 'greetings', f'Expected greetings, got {result}'
print('  PASS')

# Test 4: Decorator that accesses __name__
print('Test 4: Decorator that accesses __name__')
def name_logger(func):
    print(f'  func.__name__ = {func.__name__}')
    @wraps(func)
    def inner(*args, **kwargs):
        return func(*args, **kwargs)
    return inner

class Test4:
    @method_decorator(name_logger)
    def my_method(self):
        return 'done'

t4 = Test4()
result = t4.my_method()
print(f'  Result: {result}')
print('  PASS')

print()
print('All tests passed!')
""}

